tool_input.code:
import pandas as pd
import ast

df = pd.read_csv('/work/ferc_search_20260615_031225.csv')

def is_rm26_4(docket_str):
    if pd.isna(docket_str):
        return False
    try:
        dockets = ast.literal_eval(docket_str)
        return 'RM26-4-000' in dockets
    except:
        return False

def get_authors(aff_str):
    if pd.isna(aff_str):
        return []
    try:
        affs = ast.literal_eval(aff_str)
        return [a.replace("AUTHOR: ", "").strip() for a in affs if a.startswith("AUTHOR:")]
    except:
        return []

df_rm = df[df['docket_numbers'].apply(is_rm26_4)].copy()
df_rm['authors'] = df_rm['affiliations'].apply(get_authors)

# Find which filings have Indicated PJM Transmission Owners listed multiple times
# (the 4 count could be 1 filing where it's listed 4 times in affiliations)
mask = df_rm['authors'].apply(lambda x: 'Indicated PJM Transmission Owners' in x)
for idx, row in df_rm[mask].iterrows():
    print(f"Title: {row['title'][:120]}")
    print(f"Date: {row['filed_date']}")
    print(f"Authors: {row['authors']}")
    print(f"Count of 'Indicated PJM TOs' in raw: {row['affiliations'].count('Indicated PJM Transmission Owners')}")
    print()

